    private fun exceedsMaxLineLengthWhenReplacingWhitespaceAfterColonWithSingleSpace(
        colonNode: ASTNode,
        whiteSpaceAfterColon: ASTNode,
    ): Boolean {
        require(colonNode.elementType == COLON)
        require(whiteSpaceAfterColon.elementType == WHITE_SPACE)

        // Find the leaf containing the last newline before the function signature (or null when this is the first line
        // of the file).
        var prev = colonNode.prevLeaf()
        var lastLeafContainingNewline: ASTNode? = null
        var firstLeafInFile: ASTNode = colonNode
        while (prev != null) {
            firstLeafInFile = prev
            if (prev.textContains('\n')) {
                lastLeafContainingNewline = prev
                break
            }
            prev = prev.prevLeaf()
        }

        val prefix = lastLeafContainingNewline?.text?.substringAfterLast('\n').orEmpty()
        var leaf = lastLeafContainingNewline?.nextLeaf() ?: firstLeafInFile

        // Find the leaf containing the next newline after the whitespace after the colon. This newline determines the
        // end of the joined line.
        val endOfLineLeaf = whiteSpaceAfterColon.nextLeaf { it.textContains('\n') }

        val joinedLineLength =
            buildString {
                append(prefix)
                while (leaf != null && leaf != endOfLineLeaf) {
                    append(
                        if (leaf == whiteSpaceAfterColon) {
                            " "
                        } else {
                            leaf.text
                        },
                    )
                    leaf = leaf.nextLeaf()
                }
            }.length

        return joinedLineLength > maxLineLength
    }
}
"}

